import{_ as t,o,c as r,ag as a}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Recording and Playback","description":"","frontmatter":{},"headers":[],"relativePath":"guides/recording.md","filePath":"guides/recording.md"}'),d={name:"guides/recording.md"};function n(i,e,l,c,s,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="recording-and-playback" tabindex="-1">Recording and Playback <a class="header-anchor" href="#recording-and-playback" aria-label="Permalink to &quot;Recording and Playback&quot;">​</a></h1><p>The <strong>Audio Recorder</strong> module records audio directly to the SD card and plays it back, working like a simple field recorder.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><ol><li>Add an <strong>Audio Recorder</strong> module to your patch</li><li>Connect an audio source to its input (e.g., Stereo In for line input, or any module output)</li><li>Add a <strong>Stereo Out</strong> module and connect the recorder&#39;s outputs</li><li>Upload the patch</li></ol><h2 id="controls" tabindex="-1">Controls <a class="header-anchor" href="#controls" aria-label="Permalink to &quot;Controls&quot;">​</a></h2><p>The Audio Recorder auto-maps to one hardware bank:</p><table tabindex="0"><thead><tr><th>Control</th><th>Function</th></tr></thead><tbody><tr><td>Button 1</td><td>Record (press to start/stop)</td></tr><tr><td>Button 2</td><td>Play / Pause</td></tr><tr><td>Button 3</td><td>Previous file</td></tr><tr><td>Button 4</td><td>Next file</td></tr><tr><td>Pot 1</td><td>Input gain</td></tr><tr><td>Pot 2</td><td>Monitor level</td></tr></tbody></table><h2 id="file-management" tabindex="-1">File Management <a class="header-anchor" href="#file-management" aria-label="Permalink to &quot;File Management&quot;">​</a></h2><p>Recordings are saved as WAV files on the SD card:</p><ul><li>Format: 16-bit stereo, 48 kHz</li><li>Filename pattern: <code>{prefix}/{prefix}_001.wav</code>, <code>{prefix}_002.wav</code>, etc.</li><li>The prefix is set in the module&#39;s inspector (default: &quot;rec&quot;)</li></ul><h2 id="downloading-recordings" tabindex="-1">Downloading Recordings <a class="header-anchor" href="#downloading-recordings" aria-label="Permalink to &quot;Downloading Recordings&quot;">​</a></h2><p>You can download recordings from the SD card to your computer using the <strong>Recording Browser</strong> in the patcher:</p><ol><li>Connect to the board</li><li>Open the Recording Browser from the toolbar</li><li>Browse folders and files on the SD card</li><li>Click a file to download it</li></ol><h2 id="playback-folder" tabindex="-1">Playback Folder <a class="header-anchor" href="#playback-folder" aria-label="Permalink to &quot;Playback Folder&quot;">​</a></h2><p>Set the <code>playback_folder</code> parameter in the inspector to play files from any folder on the SD card, not just the recorder&#39;s own recordings.</p><h2 id="trigger-mode" tabindex="-1">Trigger Mode <a class="header-anchor" href="#trigger-mode" aria-label="Permalink to &quot;Trigger Mode&quot;">​</a></h2><p>Enable trigger mode and connect a gate signal to use the recorder as a round-robin sample player -- each gate trigger plays the next file in sequence. Useful for installations.</p>',17)])])}const g=t(d,[["render",n]]);export{p as __pageData,g as default};
